import React, { useEffect } from 'react'
import { Link, useParams, useNavigate, useLocation } from 'react-router-dom'
import { useDispatch, useSelector } from 'react-redux'

import './CartScreen.css'
import { addToCart } from '../slices/cart/cartSlice'
import Breadcrumbs from '../components/Breadcrumbs'


function CartScreen() {
  const { id } = useParams();
  const location = useLocation();
  const navigate = useNavigate();
  const dispatch = useDispatch();

  // get the selected quantity from the url
  const qty = location.search ? Number(location.search.split('=')[1]) : 1

  const cart = useSelector(state => state.cart);
  const { cartItems } = cart;

  useEffect(() => {
    if(id){
      dispatch(addToCart(id, qty))
    }
  }, [dispatch, id, qty]);

  return (
    <div>
      <Breadcrumbs>Cart</Breadcrumbs>
      <div className='cart'>
        <h1 className='title'>Cart</h1>
        {cartItems.length === 0 
          ? <p>You don't have any items in your cart yet. <Link className='no-items' to='/'>Continue shopping.</Link></p>
            : <form className='cart-form'>
                <table className='cart-items'>
                  <thead>
                    <tr>
                      <th className='first'>PRODUCT</th>
                      <th>PRICE</th>
                      <th>QUANTITY</th>
                      <th className='last' colSpan="2">TOTAL</th>
                    </tr>
                  </thead>
                  <tbody>
                    {cartItems.map((item) => (
                      <tr className='cart-item' key={item.product}>

                        <td className='product-item'>
                          <Link to={`/products/${item.product}`}><img src={item.image} alt={item.name}></img></Link>
                          <span className='product-item-details'>
                            <Link to={`/products/${item.id}`}>{item.name}</Link>
                            <span style={{fontSize:'smaller'}}><br/>{item.brand.toUpperCase()}</span>
                          </span>
                        </td>

                        <td className='price' data-title='Price'><span className='money'>{item.price}</span></td>
                        <td className='quantity' data-title='Quantity'>
                          <input type='text' value={qty} onChange={(e) => item.qty=e.target.value}></input>
                        </td>
                        <td className='total' data-title='Total'><span className='money'>{item.price * item.qty}&euro;</span></td>
                      </tr>
                    ))
                    }
                  </tbody>
                </table>
              </form>
        }
      </div>
      
    </div>
  )
}

export default CartScreen;
